## Express.js with JWT Authentication

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const router = express.Router();

// Authentication middleware
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
};

// Protected settings endpoint
router.get('/api/v1/settings', authenticateToken, async (req, res) => {
  try {
    // Get user-specific settings
    const userId = req.user.id;
    const settings = await getUserSettings(userId);

    res.json({
      success: true,
      data: settings
    });
  } catch (error) {
    res.status(500).json({ 
      error: 'Failed to retrieve settings' 
    });
  }
});

module.exports = router;
```

## Flask with JWT Authentication

```python
from flask import Flask, request, jsonify
from functools import wraps
import jwt
import os

app = Flask(__name__)

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')

        if not token:
            return jsonify({'error': 'Access token required'}), 401

        try:
            # Remove 'Bearer ' prefix if present
            if token.startswith('Bearer '):
                token = token[7:]

            data = jwt.decode(token, os.getenv('JWT_SECRET'), algorithms=['HS256'])
            current_user_id = data['user_id']
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 403
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 403

        return f(current_user_id, *args, **kwargs)
    return decorated

@app.route('/api/v1/settings', methods=['GET'])
@token_required
def get_settings(current_user_id):
    try:
        # Get user-specific settings
        settings = get_user_settings(current_user_id)

        return jsonify({
            'success': True,
            'data': settings
        })
    except Exception as e:
        return jsonify({'error': 'Failed to retrieve settings'}), 500
